const floor = -100;
const band = '2.4 GHz';
const defaultWidth = 22;
const xmin = 2400;
const xmax = 2500;

function colorForSignal(signal) {
  if (signal >= -55) return '#73bf69';
  if (signal >= -67) return '#f2cc0c';
  if (signal >= -80) return '#ff9830';
  return '#d44a3a';
}

function sanitizeName(name, bssid) {
  const s = name || '(unknown)';
  if (s === '(hidden)') {
    return `(hidden) ${String(bssid || '').slice(-4)}`;
  }
  return s;
}

const aps = [];

for (const frame of context.panel.data.series) {
  const valueField = frame.fields.find((f) => f.type === 'number');
  if (!valueField || !valueField.values || valueField.values.length === 0) {
    continue;
  }

  const labels = valueField.labels || {};
  const ssid = labels.ssid || '(unknown)';
  const bssid = labels.bssid || '';
  const freq = Number(labels.freq);
  if (!Number.isFinite(freq)) {
    continue;
  }

  let signal = null;
  for (let i = valueField.values.length - 1; i >= 0; i--) {
    const v = Number(valueField.values[i]);
    if (Number.isFinite(v)) {
      signal = v;
      break;
    }
  }
  if (!Number.isFinite(signal)) {
    continue;
  }

  aps.push({ ssid, bssid, freq, signal, name: sanitizeName(ssid, bssid) });
}

aps.sort((a, b) => a.freq - b.freq || b.signal - a.signal || a.name.localeCompare(b.name));

const freqCounts = new Map();
for (const ap of aps) {
  freqCounts.set(ap.freq, (freqCounts.get(ap.freq) || 0) + 1);
}

const freqLines = Array.from(freqCounts.entries())
  .sort((a, b) => a[0] - b[0])
  .map(([freq, count]) => ({
    xAxis: freq,
    label: { formatter: count > 1 ? `${freq} MHz\n${count} APs` : `${freq} MHz` }
  }));

const series = aps.map((ap, idx) => {
  const width = defaultWidth;
  const half = width / 2;
  const sigma = half / 2.15;
  const start = Math.max(xmin, ap.freq - width * 1.25);
  const end = Math.min(xmax, ap.freq + width * 1.25);
  const samples = 41;
  const data = [];

  for (let i = 0; i < samples; i++) {
    const x = start + ((end - start) * i) / (samples - 1);
    const g = Math.exp(-0.5 * Math.pow((x - ap.freq) / sigma, 2));
    // Convert negative dBm into a visible lobe from floor -> signal.
    const y = floor + (ap.signal - floor) * g;
    data.push([Number(x.toFixed(2)), Number(y.toFixed(1))]);
  }

  const color = colorForSignal(ap.signal);
  return {
    name: `${ap.freq} MHz · ${ap.name}`,
    type: 'line',
    data,
    smooth: true,
    showSymbol: false,
    symbol: 'circle',
    lineStyle: { width: 1.4, color, opacity: 0.85 },
    areaStyle: { color, opacity: 0.18 },
    emphasis: {
      focus: 'series',
      lineStyle: { width: 3, opacity: 1 },
      areaStyle: { opacity: 0.35 }
    },
    markPoint: {
      symbol: 'circle',
      symbolSize: 9,
      silent: false,
      itemStyle: { color, borderColor: '#ffffff', borderWidth: 1 },
      label: {
        show: true,
        formatter: ap.name,
        position: 'top',
        distance: 5,
        color: '#c7d0d9',
        fontSize: 10,
        overflow: 'truncate',
        width: 105,
        textBorderColor: '#111827',
        textBorderWidth: 3
      },
      data: [{
        coord: [ap.freq, ap.signal],
        name: ap.name,
        value: Number(ap.signal.toFixed(1)),
        ssid: ap.ssid,
        bssid: ap.bssid,
        freq: ap.freq,
        signal: ap.signal
      }]
    }
  };
});

// Add one invisible scatter series so tooltips directly on peaks show AP metadata.
series.push({
  name: 'AP peaks',
  type: 'scatter',
  data: aps.map((ap) => ({
    value: [ap.freq, ap.signal],
    ssid: ap.ssid,
    bssid: ap.bssid,
    freq: ap.freq,
    signal: ap.signal,
    name: ap.name
  })),
  symbolSize: 12,
  itemStyle: { opacity: 0 },
  tooltip: { show: true },
  z: 20
});

return {
  backgroundColor: 'transparent',
  animation: false,
  tooltip: {
    trigger: 'item',
    confine: true,
    formatter: (params) => {
      const d = params.data || {};
      if (d.ssid || d.bssid || d.freq) {
        return [
          `<b>${d.ssid || d.name || '(unknown)'}</b>`,
          `BSSID: ${d.bssid || '-'}`,
          `Frequency: ${d.freq} MHz`,
          `Signal: ${Number(d.signal ?? params.value?.[1]).toFixed(1)} dBm`,
          `Approx width: ${defaultWidth} MHz`
        ].join('<br/>');
      }
      return `${params.seriesName}<br/>${params.value?.[0]} MHz: ${params.value?.[1]} dBm`;
    }
  },
  legend: {
    show: false,
    type: 'scroll',
    top: 0,
    textStyle: { color: '#c7d0d9' }
  },
  grid: { left: 58, right: 24, top: 24, bottom: 58, containLabel: true },
  xAxis: {
    type: 'value',
    name: 'Frequency (MHz)',
    nameLocation: 'middle',
    nameGap: 36,
    min: xmin,
    max: xmax,
    axisLabel: { formatter: '{value}' },
    splitLine: { show: true, lineStyle: { opacity: 0.22 } }
  },
  yAxis: {
    type: 'value',
    name: 'Signal (dBm)',
    min: floor,
    max: 0,
    axisLabel: { formatter: '{value}' },
    splitLine: { show: true, lineStyle: { opacity: 0.22 } }
  },
  graphic: aps.length === 0 ? [{
    type: 'text', left: 'center', top: 'middle',
    style: { text: `No ${band} AP data`, fill: '#c7d0d9', fontSize: 16 }
  }] : [],
  series: [
    {
      name: 'Frequency occupancy',
      type: 'line',
      data: [],
      markLine: {
        symbol: 'none',
        silent: true,
        lineStyle: { color: '#8ab8ff', type: 'dashed', opacity: 0.18 },
        label: { color: '#8ab8ff', fontSize: 9, position: 'insideEndTop' },
        data: freqLines
      }
    },
    ...series
  ]
};

